#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1 = vec2(vUv.x-.5,vUv.y-0.5)*uAspect.xy;

//STONE
float dist = 40+18*iter6;
uv3 = dist * (uv1) + dist*vec2(0,sin(q15))*0;
float ky = clamp01(.04-uv3.y/40);
float k1 = uv3.x ;;
k1 = k1 - sign (k1)*14; //Verdoppelung
k1 = k1 - sign (k1)*q28*2; //Verdoppelung
k1 = k1 - sign (k1)*8; //Verdoppelung

float ff = 16 + 16*rand_preset.z;
int n = 1 ;
while (n <= 4+2*iter6)
{
  k1 += (-ff*n*sign(k1))*ky*ky;
  ky = clamp01(ky - .1);
  n++;
}
k1 = clamp(k1,-1.57,1.57);
stone = clamp01(cos(k1)-.02) ;

light = 0; trel = uTime*.2;
for (int m= 1; m<= 3; m++)
{//Kugel1
  rsk = (uv1 + .3*vec2 (cos(q15/m)*(m%2),cos(q16/m)*((m+1)%2))) ;
  dz1 = normalize(rsk);
  rad1 = 16*length(rsk) * (2+cos(q17*m)) ;
  uv4 =  tan(rad1)*dz1;
  mask1 = clamp01(9-7*rad1);
  Kugel1 = uv4*mask1;
  light += (.1/rad1)*pow(q23,1+slow_roam_sin);;
  vUv=  vUv+Kugel1*.1;
}

vUv+=stone*.05;
//Fractal Distortion
vec2 z = (vUv.yx-.5)*(2+stone);
vec2 uv2 = cpow(z,.5+.3*q28/8)%clip1;

uv2 = 0.5 + (1.0 -abs(fract(uv2 * 0.5)*2 - 1.0 )-0.5)*1; // Eo.S. mirror code
ret = (texture(sampler_main, uv2.yx) + GetPixel(vUvOriginal))/2;
//ret += .002/length(uv1);

//LASER
uv4 = vUv-.5-lpos1+stone;
uv5  = normalize(uv4)-vec2(q10,q11);
ray1 = clamp01(1-length(uv5/q12));
ray1 += pow(.0005/length(uv5),1)/length(uv4);
sun1 = clamp01(.002/length(uv4))/(1.05-q12);

ret += (ray1+sun1)*fract(vec3(q27,q27+3,q27+6)/16);
ret += (.015/length(sin(uv2*2+.2*(q27%8-4))));
ret += pow(stone,3)*q29*(1+roam_sin);
ret += light;
ret *= 1-.11*30/uFps-.02*lum(GetBlur2(vUvOriginal));

  fragColor = ret;
}

